/**
 * wp_logo_data.js
 * Externalized logo as a Data URI to avoid offline/canvas security issues from file/logo paths.
 * Exposes:
 *   window.WP_LOGO_DATA_URI
 *   window.applyWardrobeProLogo()
 */
/* global window, document, MutationObserver */
(function () {
  'use strict';

  // Full data URI (png, base64)
  var DATA_URI =
    'data:image/png;base64,';

  // Export to global (so other scripts can use it)
  window.WP_LOGO_DATA_URI = DATA_URI;

  function applyWardrobeProLogo() {
    try {
      var uri = window.WP_LOGO_DATA_URI;
      if (!uri || typeof uri !== 'string') return;

      var nodes = document.querySelectorAll('img.header-logo, img[data-wp-logo="1"], #wpHeaderLogo');
      for (var i = 0; i < nodes.length; i++) {
        var img = nodes[i];
        // Only override if empty or pointing to old asset
        var cur = (img.getAttribute('src') || '').trim();
        if (!cur || cur === 'logo.png' || cur.endsWith('/logo.png')) {
          img.setAttribute('src', uri);
        } else if (cur.startsWith('data:')) {
          // already embedded
        } else {
          // If something else is used, don't force override.
        }
      }
    } catch (_e) {
      // silent
    }
  }

  window.applyWardrobeProLogo = applyWardrobeProLogo;

  function _startLogoObserver() {
    try {
      // React renders after DOMContentLoaded sometimes; also React re-renders can reset `src`.
      // Observe the DOM briefly and re-apply the embedded logo when matching <img> nodes appear/change.
      var root = document && document.documentElement;
      if (!root) return;
      if (typeof MutationObserver !== 'function') return;

      var scheduled = false;
      function scheduleApply() {
        if (scheduled) return;
        scheduled = true;
        setTimeout(function () {
          scheduled = false;
          applyWardrobeProLogo();
        }, 0);
      }

      var obs = new MutationObserver(function (mutations) {
        for (var i = 0; i < mutations.length; i++) {
          var m = mutations[i];
          if (m.type === 'childList') {
            if (m.addedNodes && m.addedNodes.length) {
              scheduleApply();
              return;
            }
          } else if (m.type === 'attributes') {
            if (m.attributeName === 'src') {
              scheduleApply();
              return;
            }
          }
        }
      });

      obs.observe(root, {
        subtree: true,
        childList: true,
        attributes: true,
        attributeFilter: ['src'],
      });

      // A few extra delayed attempts (cheap insurance for slow mounts).
      setTimeout(applyWardrobeProLogo, 25);
      setTimeout(applyWardrobeProLogo, 150);
      setTimeout(applyWardrobeProLogo, 600);

      // Stop observing after a short window to avoid permanent overhead.
      setTimeout(function () {
        try {
          obs.disconnect();
        } catch (_e) {
          // ignore
        }
      }, 10000);
    } catch (_e) {
      // ignore
    }
  }

  if (document && document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function () {
      applyWardrobeProLogo();
      _startLogoObserver();
    });
  } else {
    applyWardrobeProLogo();
    _startLogoObserver();
  }
})();
